'use client';

import { useEffect, useState } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { getSessionById, getOrganizationById } from '@/lib/db';
import type { Session, Organization, Agenda, Talk, Member } from '@/types';


export default function OutputPage() {
  const params = useParams();
  const router = useRouter();
  const sessionId = params.sessionId as string;

  const [session, setSession] = useState<Session | null>(null);
  const [organization, setOrganization] = useState<Organization | null>(null);
  const [isSignedIn, setIsSignedIn] = useState(false);

  useEffect(() => {
    (async () => {
      const s = await getSessionById(sessionId);
      if (!s) {
        console.warn('[OutputPage] session not found:', sessionId);
        return;
      }
      setSession(s);

      const org = await getOrganizationById(s.organizationId);
      if (org) setOrganization(org);
    })();
  }, [sessionId]);

  // Google API初期化
  useEffect(() => {
    if (typeof window === 'undefined') return;
    let gapi: any;
    import('gapi-script').then((mod) => {
      gapi = mod.gapi;
      const initClient = () => {
        gapi.client.init({
          clientId: process.env.NEXT_PUBLIC_GOOGLE_CLIENT_ID || 'YOUR_CLIENT_ID',
          scope: 'https://www.googleapis.com/auth/spreadsheets',
        }).then(() => {
          const auth = gapi.auth2.getAuthInstance();
          setIsSignedIn(auth.isSignedIn.get());
          auth.isSignedIn.listen(setIsSignedIn);
        });
      };
      gapi.load('client:auth2', initClient);
    });
  }, []);

  if (!session || !organization) {
    return <div className="min-h-screen bg-[#0f0f0f] text-white flex items-center justify-center">読み込み中...</div>;
  }

  // 統計情報計算
  const totalTalks = session.agendas.reduce((sum, agenda) => sum + agenda.talks.length, 0);
  const meetingDuration = session.status === 'completed'
    ? Math.floor((new Date(session.updatedAt).getTime() - new Date(session.createdAt).getTime()) / (1000 * 60)) + '分'
    : '進行中';
  const participantCount = session.members.length;
  const agendaCount = session.agendas.length;

  // 役職別メンバー
  const chair = session.members.find(m => m.role === 'chair');
  const vice = session.members.find(m => m.role === 'vice');
  const attendees = session.members.map(m => `${m.lastName}${m.firstName ? ' ' + m.firstName : ''}`).join('、');

  // 話者名取得関数
  const getSpeakerName = (speakerId: string): string => {
    if (speakerId === '__unknown__') return '不明';
    const member = session.members.find(m => m.id === speakerId);
    return member ? `${member.lastName}${member.firstName ? ' ' + member.firstName : ''}` : '不明';
  };

  // PDF生成関数
  const generatePDF = async () => {
    if (typeof window === 'undefined') return;
    const html2pdf = (await import('html2pdf.js')).default;

    // oklchカラーを一時的に無効化するstyleタグを追加
    const style = document.createElement('style');
    style.id = 'disable-oklch';
    style.textContent = `
      * {
        color: #000 !important;
        background: #fff !important;
        border-color: #000 !important;
      }
      body, html {
        color: #000 !important;
        background: #fff !important;
      }
    `;
    document.head.appendChild(style);

    const sourceDiv = document.getElementById('pdf-content');
    if (!sourceDiv) {
      document.head.removeChild(style);
      return;
    }

    const opt = {
      margin: 1,
      filename: `${session?.title || '議事録'}.pdf`,
      image: { type: 'jpeg' as const, quality: 0.98 },
      html2canvas: { scale: 1, useCORS: true },
      jsPDF: { unit: 'in' as const, format: 'letter' as const, orientation: 'portrait' as const },
    };

    try {
      await html2pdf().set(opt).from(sourceDiv).save();
    } finally {
      // styleタグを削除
      document.head.removeChild(style);
    }
  };

  // Google認証
  const signIn = async () => {
    if (typeof window === 'undefined') return;
    const { gapi } = await import('gapi-script');
    gapi.auth2.getAuthInstance().signIn();
  };

  // Google Sheetsにエクスポート
  const exportToSheets = async () => {
    if (!session || !organization) return;
    if (typeof window === 'undefined') return;
    const { gapi } = await import('gapi-script');

    try {
      // 新しいスプレッドシート作成
      const response = await gapi.client.sheets.spreadsheets.create({
        properties: {
          title: `${organization.name} - ${session.title}`,
        },
      });
      const spreadsheetId = response.result.spreadsheetId;

      // データ準備
      const values = [
        [organization.name],
        [organization.groupName || ''],
        [session.title],
        ['日時', new Date(session.datetime).toLocaleString('ja-JP')],
        ['場所', session.location],
        ['議長', chair ? `${chair.lastName}${chair.firstName ? ' ' + chair.firstName : ''}` : '未設定'],
        ['副議長', vice ? `${vice.lastName}${vice.firstName ? ' ' + vice.firstName : ''}` : '未設定'],
        ['出席者', attendees],
        [],
        ['議題', '話者', '時刻', '発言内容'],
      ];

      session.agendas.forEach((agenda) => {
        agenda.talks.forEach((talk) => {
          values.push([
            agenda.title,
            getSpeakerName(talk.speakerId),
            new Date(talk.savedAt).toLocaleString('ja-JP'),
            talk.text,
          ]);
        });
      });

      // データを書き込み
      await gapi.client.sheets.spreadsheets.values.update({
        spreadsheetId,
        range: 'A1',
        valueInputOption: 'RAW',
        resource: { values },
      });

      alert(`Google Sheetsにエクスポートしました: https://docs.google.com/spreadsheets/d/${spreadsheetId}`);
    } catch (error) {
      console.error('Sheets export error:', error);
      alert('エクスポートに失敗しました。');
    }
  };

  return (
    <div className="min-h-screen bg-[#0f0f0f] text-white flex">
      {/* 左ペイン：議事録プレビュー */}
      <div id="pdf-content" style={{ flex: 1, padding: 32, backgroundColor: '#0f0f0f', color: '#fff', minHeight: '100vh' }}>
        <div style={{ maxWidth: 896, margin: '0 auto' }}>
          {/* 組織情報 */}
          <div style={{ marginBottom: 32 }}>
            <h1 style={{ fontSize: 24, fontWeight: 'bold', marginBottom: 8 }}>{organization.name}</h1>
            {organization.groupName && <h2 style={{ fontSize: 20, marginBottom: 8 }}>{organization.groupName}</h2>}
            <h3 style={{ fontSize: 18 }}>{session.title}</h3>
          </div>

          {/* 会議情報 */}
          <div style={{ marginBottom: 32 }}>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16, marginBottom: 16 }}>
              <div><strong>日時：</strong>{new Date(session.datetime).toLocaleString('ja-JP')}</div>
              <div><strong>場所：</strong>{session.location}</div>
            </div>
            <div style={{ marginBottom: 8 }}><strong>議長：</strong>{chair ? `${chair.lastName}${chair.firstName ? ' ' + chair.firstName : ''}` : '未設定'}</div>
            <div style={{ marginBottom: 8 }}><strong>副議長：</strong>{vice ? `${vice.lastName}${vice.firstName ? ' ' + vice.firstName : ''}` : '未設定'}</div>
            <div><strong>出席者：</strong>{attendees}</div>
          </div>

          {/* 議題ごとのトーク */}
          {session.agendas.map((agenda, index) => (
            <div key={agenda.id} style={{ marginBottom: 32 }}>
              <h4 style={{ fontSize: 18, fontWeight: 600, marginBottom: 16 }}>{index + 1}. {agenda.title}</h4>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
                {agenda.talks.map((talk) => (
                  <div key={talk.id} style={{ borderLeft: '4px solid #666', paddingLeft: 16 }}>
                    <div style={{ display: 'flex', alignItems: 'center', marginBottom: 4 }}>
                      <span style={{ fontWeight: 500, marginRight: 8 }}>{getSpeakerName(talk.speakerId)}</span>
                      <span style={{ fontSize: 14, color: '#ccc' }}>{new Date(talk.savedAt).toLocaleTimeString('ja-JP', { hour: '2-digit', minute: '2-digit' })}</span>
                    </div>
                    <div style={{ color: '#eee', whiteSpace: 'pre-wrap' }}>{talk.text}</div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* 右ペイン：サイドバー */}
      <div style={{ width: 320, backgroundColor: '#1a1a1a', padding: 24 }}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>
          <button onClick={generatePDF} style={{ width: '100%', backgroundColor: '#2563eb', color: '#fff', border: 'none', padding: '12px 0', borderRadius: 6, fontWeight: 600, cursor: 'pointer' }}>
            PDFで出力
          </button>
          {!isSignedIn ? (
            <button onClick={signIn} style={{ width: '100%', backgroundColor: '#16a34a', color: '#fff', border: 'none', padding: '12px 0', borderRadius: 6, fontWeight: 600, cursor: 'pointer' }}>
              Googleにログイン
            </button>
          ) : (
            <button onClick={exportToSheets} style={{ width: '100%', backgroundColor: '#dc2626', color: '#fff', border: 'none', padding: '12px 0', borderRadius: 6, fontWeight: 600, cursor: 'pointer' }}>
              Google Sheetsにエクスポート
            </button>
          )}

          <div>
            <h4 style={{ fontSize: 18, fontWeight: 600, marginBottom: 16, color: '#fff' }}>統計情報</h4>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8, fontSize: 14, color: '#fff' }}>
              <div>総発言数：{totalTalks}</div>
              <div>会議時間：{meetingDuration}</div>
              <div>参加者数：{participantCount}</div>
              <div>議題数：{agendaCount}</div>
            </div>
          </div>

          <button onClick={() => router.push('/')} style={{ width: '100%', backgroundColor: 'transparent', color: '#fff', border: '1px solid #666', padding: '12px 0', borderRadius: 6, fontWeight: 600, cursor: 'pointer' }}>
            ホームへ戻る
          </button>
        </div>
      </div>
      {/* PDF出力用の隠しdiv */}
      <div id="pdf-hidden" style={{ display: 'none' }} />
    </div>
  );
}